import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract RefundEscrow is ReentrancyGuard {
    address public immutable payer;
    address public immutable payee;
    address public immutable arbiter;
    bool public refundsEnabled;
    mapping(address => uint256) public withdrawnAmounts;

    event Deposit(address indexed sender, uint256 amount);
    event Release();
    event EnableRefunds();
    event Refund(address indexed sender, uint256 amount);
    event State(bool refundsEnabled, bool canWithdraw);

    constructor(address _payer, address _payee, address _arbiter) {
        require(_payer != address(0) && _payee != address(0) && _arbiter != address(0), "Invalid address");
        require(_payer != _payee && _payer != _arbiter && _payee != _arbiter, "Duplicate addresses");
        payer = _payer;
        payee = _payee;
        arbiter = _arbiter;
        refundsEnabled = false;
    }

    function deposit() external payable {
        require(msg.value > 0, "Deposit amount must be greater than 0");
        require(msg.sender == payer, "Only payer can deposit");
        emit Deposit(msg.sender, msg.value);
    }

    function release() external nonReentrant {
        require(msg.sender == arbiter, "Only arbiter can release");
        require(!refundsEnabled, "Refunds already enabled");
        uint256 balance = address(this).balance;
        (bool sent,) = payee.call{value: balance}("");
        require(sent, "Failed to send Ether");
        emit Release();
    }

