        require(sent, "Failed to send Ether");
        emit Refund(msg.sender, amountToWithdraw);
    }

    function getBalance() external view returns (uint256) {
        return address(this).balance;
    }

    function getState() external view returns (bool, bool) {
        return (refundsEnabled, address(this).balance > withdrawnAmounts[payer]);
    }
}
